
.active-color {
  color: #e53a40;
}
.myOrder-view {
  position: relative;
  width: 10rem;
  margin: 0 auto;
  background-color: #fff;
  font-family: "PingFang SC";
}
.myOrder-view .header {
    position: fixed;
    z-index: 100;
    top: 0;
    left: 0;
    right: 0;
}
.myOrder-view .header .mint-navbar {
      border-bottom: 1px solid #e4e4e4;
}
.myOrder-view .header .mint-tab-item-label {
      font-size: .4rem;
      line-height: .4rem;
      color: #5a5a5a;
}
.myOrder-view .header .mint-navbar .mint-tab-item {
      padding: .4rem 0;
      height: 1.2rem;
      line-height: .4rem;
}
.myOrder-view .header .mint-navbar .mint-tab-item.is-selected {
      border-bottom: 3px solid #e53a40;
      color: #e53a40;
      margin-bottom: 0px;
}
.myOrder-view .main {
    width: 100%;
    margin-top: 1.52rem;
    background-color: #fff;
}
.myOrder-view .main .order-list {
      background-color: #f7f7f7;
      text-align: left;
}
.myOrder-view .main .order-list .order-wrapper {
        padding: 0 0 0.4rem 0.4rem;
        margin-top: .32rem;
        background-color: #fff;
        font-size: .3733rem;
}
.myOrder-view .main .order-list .order-wrapper .date {
          font-size: .2933rem;
          color: #5a5a5a;
          font-family: NotoSansHans;
          line-height: 1rem;
          border-bottom: 1px solid #e4e4e4;
}
.myOrder-view .main .order-list .order-wrapper .prod-list {
          position: relative;
}
.myOrder-view .main .order-list .order-wrapper .prod-list li {
            position: relative;
            border-bottom: 1px solid #e4e4e4;
            padding: .32rem 0;
}
.myOrder-view .main .order-list .order-wrapper .total-price {
          line-height: 1.2rem;
          text-align: right;
          padding-right: .4rem;
          font-size: .32rem;
          font-family: "PingFang SC";
}
.myOrder-view .main .order-list .order-wrapper .operate {
          text-align: right;
          padding-right: .2rem;
}
.myOrder-view .main .order-list .order-wrapper .operate .mint-button--small {
            font-size: .32rem;
            padding: 0;
            line-height: .72rem;
            height: .72rem;
            width: 1.8rem;
            margin-right: .2rem;
}



