
.storeCollect-view {
  width: 100%;
  background-color: #fff;
  font-family: NotoSansHans;
  text-align: left;
}
.storeCollect-view .active-color {
    color: #e53a40;
}
.storeCollect-view .list-wrapper {
    padding: .2rem .52rem;
}
.storeCollect-view .list-wrapper .store-list li {
      padding: .2rem 0;
      margin: .2rem 0;
}
.storeCollect-view .list-wrapper .store-list li .wrapper {
        position: relative;
        width: 100%;
        padding-left: 1.72rem;
        height: 100%;
}
.storeCollect-view .list-wrapper .store-list li .img-wrapper {
        position: absolute;
        left: 0;
        top: 0;
        width: 1.32rem;
        height: 1.32rem;
}
.storeCollect-view .list-wrapper .store-list li .img-wrapper img {
          width: 100%;
          height: 100%;
}
.storeCollect-view .list-wrapper .store-list li .text-wrapper {
        height: 1.32rem;
        padding-right: 2rem;
}
.storeCollect-view .list-wrapper .store-list li .text-wrapper .name {
          font-size: .3733rem;
          line-height: .8rem;
          color: #222;
          font-weight: 500;
}
.storeCollect-view .list-wrapper .store-list li .text-wrapper .count {
          font-size: .32rem;
          color: #b0b0b0;
          font-weight: 300;
}
.storeCollect-view .list-wrapper .store-list li .btn-wrapper {
        position: absolute;
        right: 0;
        top: .4rem;
        z-index: 200;
}
.storeCollect-view .list-wrapper .store-list li .btn-wrapper .mint-button {
          color: #fff;
          font-size: .32rem;
          height: .6133rem;
          width: 1.6rem;
          line-height: .6133rem;
          padding: 0;
          border: none;
}



