
.index-view {
  width: 100%;
}
.index-view .search-wrapper {
    position: fixed;
    /*top:.26rem;*/
    left: 50%;
    -webkit-transform: translate3d(-50%, 0, 0);
    transform: translate3d(-50%, 0, 0);
    z-index: 1000;
    width: 10rem;
    padding: .26rem 0;
}
.index-view .scroll-view {
    width: 10rem;
    margin: 0 auto;
    background-color: #fff;
    -webkit-transform: translate3d(0, 0, 0);
    transform: translate3d(0, 0, 0);
}
.index-view .scroll-view .banner {
      width: 10rem;
      height: 4.8rem;
}
.index-view .scroll-view .banner img {
        width: 100%;
        height: 100%;
}
.index-view .scroll-view .banner .mint-swipe-indicator {
        background: #fff;
        opacity: 1;
}
.index-view .scroll-view .banner .mint-swipe-indicator.is-active {
        background: #e53a40;
}
.index-view .scroll-view .nav {
      width: 100%;
      padding: .6rem .27rem;
      background-color: #fff;
}
.index-view .scroll-view .nav li {
        float: left;
        width: 25%;
}
.index-view .scroll-view .nav li > div {
          color: #5a5a5a;
          diaplay: block;
}
.index-view .scroll-view .nav li > div .title {
            color: #e53a40;
            font-size: .62rem;
            line-height: 1.2rem;
            font-family: NotoSansHans;
            font-weight: 900;
}
.index-view .scroll-view .nav li > div .text {
            font-size: .24rem;
            line-height: .6rem;
}
.index-view .scroll-view .my-swiper {
      width: 100%;
}
.index-view .scroll-view .my-swiper .swiper-wrapper {
        -webkit-transform: translate3d(-4.86rem, 0, 0);
        transform: translate3d(-4.86rem, 0, 0);
}
.index-view .scroll-view .my-swiper .swiper-slide {
        position: relative;
        width: 6.4rem;
        height: 3.73rem;
        margin-right: .26rem;
}
.index-view .scroll-view .my-swiper .swiper-slide img {
          width: 100%;
          height: 3.73rem;
}
.index-view .scroll-view .my-swiper .swiper-slide .mask {
          position: absolute;
          left: 0;
          right: 0;
          top: 0;
          bottom: 0;
          padding: .26rem;
          background-color: rgba(30, 30, 30, 0.5);
          color: #fff;
          text-align: center;
          font-family: NotoSansHans;
}
.index-view .scroll-view .my-swiper .swiper-slide .mask .border {
            width: 100%;
            height: 100%;
            padding: .8rem 0;
            border: 1px solid #fff;
}
.index-view .scroll-view .my-swiper .swiper-slide .mask .border .title {
              font-size: .4533rem;
              line-height: .8rem;
              font-weight: 500;
}
.index-view .scroll-view .my-swiper .swiper-slide .mask .border .text {
              font-size: .3733rem;
              line-height: .6rem;
              font-weight: 300;
}
.index-view .scroll-view .seckill {
      position: relative;
      width: 100%;
      padding: .56rem;
      background: #fff;
      text-align: left;
      color: #b0b0b0;
}
.index-view .scroll-view .seckill > a {
        color: #b0b0b0;
        display: block;
}
.index-view .scroll-view .seckill .first-title {
        font-size: .24rem;
        line-height: .8rem;
        font-weight: normal;
}
.index-view .scroll-view .seckill .second-title {
        font-size: .48rem;
        color: #e53a40;
        line-height: .8rem;
}
.index-view .scroll-view .seckill .time {
        height: 1.06rem;
        line-height: 1.06rem;
        margin: .24rem 0;
        vertical-align: middle;
}
.index-view .scroll-view .seckill .time > span {
          display: block;
          float: left;
          height: 1.06rem;
          text-align: center;
}
.index-view .scroll-view .seckill .time .count {
          width: 1.06rem;
          background-color: #e53a40;
          color: #fff;
          font-size: .58rem;
}
.index-view .scroll-view .seckill .time .symbol {
          width: .4rem;
          font-size: .8rem;
          color: #e53a40;
}
.index-view .scroll-view .seckill img {
        position: absolute;
        right: .5rem;
        top: 1rem;
        width: 2.6rem;
        height: 2.6rem;
}
.index-view .scroll-view .fenlei {
      width: 100%;
      padding-left: .56rem;
      background-color: #fff;
      text-align: center;
      font-family: NotoSansHans;
      margin-bottom: .2rem;
}
.index-view .scroll-view .fenlei .first-title {
        text-align: left;
        color: #b0b0b0;
        font-weight: normal;
        font-size: .24rem;
        line-height: .8rem;
}
.index-view .scroll-view .fenlei .swiper-slide {
        position: relative;
        width: 3.47rem;
        height: 3.47rem;
        padding-top: .2rem;
        background-color: #f6f6f6;
        color: #022222;
        overflow: hidden;
}
.index-view .scroll-view .fenlei .swiper-slide .title {
          font-size: .453rem;
          font-weight: 500;
          line-height: .8rem;
}
.index-view .scroll-view .fenlei .swiper-slide .text {
          font-size: .373rem;
          font-weight: 300;
          line-height: .6rem;
}
.index-view .scroll-view .fenlei .swiper-slide img {
          position: absolute;
          bottom: 0;
          left: 50%;
          -webkit-transform: translate3d(-50%, 0, 0);
          transform: translate3d(-50%, 0, 0);
          width: 1.76rem;
          height: 1.493rem;
}
.index-view .scroll-view .recommend {
      width: 100%;
      background-color: #fff;
      padding-left: .56rem;
      font-family: NotoSansHans;
}
.index-view .scroll-view .recommend .first-title {
        text-align: left;
        color: #b0b0b0;
        font-weight: normal;
        font-size: .24rem;
        line-height: .8rem;
}
.index-view .scroll-view .recommend li {
        height: 1.86rem;
        text-align: left;
        margin-bottom: .4rem;
        color: #022222;
}
.index-view .scroll-view .recommend li img {
          display: inline-block;
          width: 1.86rem;
          height: 1.86rem;
}
.index-view .scroll-view .recommend li .detail {
          display: inline-block;
          height: 1.86rem;
          padding-left: .2rem;
          overflow: hidden;
}
.index-view .scroll-view .recommend li .name {
          font-size: .4533rem;
          font-weight: 500;
          /*color:#022222;*/
          line-height: .8rem;
}
.index-view .scroll-view .recommend li .tag {
          font-size: .3733rem;
          font-weight: 300;
          line-height: .6rem;
}
.index-view .scroll-view .recommend li .buyCount {
          font-size: .32rem;
          font-weight: 300;
}



