
.dark-color {
  color: #b0b0b0;
}
.active-color {
  color: #e53a40;
}
.cart-view {
  width: 100%;
  /*font-family: "PingFang SC";*/
}
.cart-view .vux-swipeout-button-warn {
    background-color: #e53a40;
}
.cart-view .mint-checkbox {
    position: relative;
    top: -2px;
}
.cart-view .mint-checkbox-core {
    border-color: #e53a40;
    width: 16px;
    height: 16px;
}
.cart-view .mint-checkbox-input[disabled] + .mint-checkbox-core {
    background-color: #fff;
    border-color: #b0b0b0;
}
.cart-view .mint-checkbox-input:checked + .mint-checkbox-core {
    background-color: #e53a40;
    border-color: #e53a40;
}
.cart-view .mint-checkbox-core::after {
    top: 2px;
    left: 5px;
    width: 3px;
    height: 6px;
}
.cart-view .pay-bar {
    position: fixed;
    bottom: 1.3333rem;
    left: 0;
    right: 0;
    z-index: 100;
    height: 1.32rem;
    line-height: 1.32rem;
    border-top: 1px solid #e4e4e4;
    background-color: #fff;
    font-size: .3466rem;
    color: #222;
    text-align: center;
}
.cart-view .pay-bar .check-all {
      width: 25%;
      height: 1.32rem;
      padding-left: .6rem;
      text-align: left;
      border-right: 1px solid #e4e4e4;
}
.cart-view .pay-bar .check-all .text {
        padding-left: .14rem;
}
.cart-view .pay-bar .pay-btn {
      width: 20%;
      height: 1.32rem;
}
.cart-view .pay-bar .pay-btn.delete-btn {
        background-color: #e53a40;
        color: #fff;
}
.cart-view .pay-bar .pay-btn.disabled {
      background-color: #e4e4e4;
      color: #5a5a5a;
}
.cart-view .pay-bar .pay-btn.active {
      background-color: #e53a40;
      color: #fff;
}
.cart-view .pay-bar .edit-btn {
      width: 18%;
      height: 1.32rem;
      border-right: 1px solid #e4e4e4;
}
.cart-view .pay-bar .price-info {
      width: 37%;
      height: 1.32rem;
      padding: .2rem .32rem 0 0;
      text-align: right;
}
.cart-view .pay-bar .price-info p {
        line-height: .48rem;
}
.cart-view .pay-bar .price-info p:nth-child(2) {
          font-size: .2933rem;
}
.cart-view .main {
    text-align: left;
    margin-bottom: 2.66rem;
}
.cart-view .main .store-wrapper {
      margin-bottom: .5333rem;
      background-color: #fff;
}
.cart-view .main .store-name {
      line-height: 1.0666rem;
      border-bottom: 1px solid #e4e4e4;
      padding: 0 .2rem 0 .6rem;
      font-family: "PingFang SC";
      font-weight: 500;
      color: #222;
}
.cart-view .main .store-name span.text {
        padding-left: .2rem;
}
.cart-view .main .store-name .edit {
        background-color: transparent;
        border: none;
        height: 100%;
        padding: 0 .2rem;
        margin-right: .2rem;
        border-radius: 2px;
}
.cart-view .main .prod-list {
      padding-left: .6rem;
}
.cart-view .main .prod-list .prod-wrapper {
        position: relative;
        height: 1.8666rem;
        padding: .6rem 0 .6rem 2.8rem;
        overflow: hidden;
        background: #fff;
        -webkit-box-sizing: content-box;
                box-sizing: content-box;
        font-size: .3466rem;
}
.cart-view .main .prod-list .prod-wrapper.is-invalid {
          color: #b0b0b0;
}
.cart-view .main .prod-list .prod-wrapper.has-border {
          border-bottom: 1px solid #e4e4e4;
}
.cart-view .main .prod-list .prod-wrapper .price {
          line-height: .52rem;
}
.cart-view .main .prod-list .prod-wrapper .price strong {
            font-size: .3466rem;
}
.cart-view .main .prod-list .prod-wrapper .style {
          line-height: .6rem;
          position: relative;
}
.cart-view .main .prod-list .prod-wrapper .style .icon-select {
            position: absolute;
            right: 1.6rem;
            top: .14rem;
            width: .32rem;
            height: .32rem;
            color: #b0b0b0;
}
.cart-view .main .prod-list .prod-wrapper .count {
          position: absolute;
          right: .6rem;
          bottom: .6rem;
          line-height: .52rem;
}
.cart-view .main .prod-list .img-wrapper {
        position: absolute;
        left: 0;
        top: .6rem;
        height: 1.8666rem;
        width: 2.5866rem;
        text-align: right;
}
.cart-view .main .prod-list .img-wrapper img {
          width: 1.8666rem;
          height: 1.8666rem;
}
.cart-view .main .prod-list .img-wrapper .checkbox-wrapper {
          position: absolute;
          left: 0;
          top: 0;
          line-height: 1.8666rem;
          height: 100%;
          width: .72rem;
          text-align: left;
}
.cart-view .main .prod-list .prod-name {
        line-height: .52rem;
        height: 1rem;
        font-size: .3466rem;
        font-weight: 500;
        display: -webkit-box;
        -webkit-box-orient: vertical;
        -webkit-line-clamp: 2;
        overflow: hidden;
}
.cart-view .edit-line {
    position: absolute;
    right: .6rem;
    bottom: .4rem;
    height: 16px;
    line-height: 16px;
    width: 1.6rem;
    text-align: center;
}
.cart-view .edit-line .circle-btn {
      position: absolute;
      top: 0;
      width: 16px;
      height: 16px;
      border-radius: 50%;
      background-color: #e53a40;
      color: #fff;
      font-size: 14px;
      font-weight: bold;
      outline: none;
      border: none;
      overflow: hidden;
}
.cart-view .edit-line .circle-btn.disabled {
        background-color: #f5b0b3;
}
.cart-view .edit-line .reduce-btn {
      left: 0;
}
.cart-view .edit-line .add-btn {
      right: 0;
}
.cart-view .edit-line .prod-count {
      font-size: .3466rem;
}
.cart-view .edit-line .icon {
      color: #fff;
      width: .32rem;
      height: .32rem;
}



