
.active-color {
  color: #e53a40;
}
.seckill-view {
  position: relative;
  /*width:10rem;*/
  margin: 0 auto;
  background-color: #fff;
  font-family: "PingFang SC";
}
.seckill-view .header {
    position: fixed;
    z-index: 100;
    top: 0;
    left: 0;
    right: 0;
}
.seckill-view .header .mint-navbar {
      background-color: #403f3f;
}
.seckill-view .header .mint-tab-item-label {
      font-size: .4533rem;
      line-height: .54rem;
      font-weight: 500;
}
.seckill-view .header .mint-tab-item-label .text {
        font-size: .2666rem;
        line-height: .4rem;
}
.seckill-view .header .mint-navbar .mint-tab-item {
      padding: .2rem 0;
      height: 1.32rem;
      color: #fff;
}
.seckill-view .header .mint-navbar .mint-tab-item.is-selected {
      border-bottom: none;
      background-color: #e53a40;
      margin-bottom: 0px;
}
.seckill-view .main {
    margin-top: 1.4rem;
}
.seckill-view .main .prod-list {
      padding: 0 .2rem;
}
.seckill-view .main .prod-list li {
        position: relative;
        padding: .32rem 0;
}
.seckill-view .main .prod-list li .img-wrapper {
          position: absolute;
          left: 0;
          top: .32rem;
          width: 2.9333rem;
          height: 2.9333rem;
}
.seckill-view .main .prod-list li .img-wrapper img {
            width: 100%;
            height: 100%;
}
.seckill-view .main .prod-list li .text-wrapper {
          padding: 0 1rem 0 3.2rem;
          text-align: left;
          height: 2.9333rem;
          /*overflow:hidden;*/
}
.seckill-view .main .prod-list li .text-wrapper .name {
            font-size: .3733rem;
            font-weight: 500;
            line-height: .52rem;
            color: #222;
            height: 1rem;
            display: -webkit-box;
            -webkit-box-orient: vertical;
            -webkit-line-clamp: 2;
            overflow: hidden;
}
.seckill-view .main .prod-list li .text-wrapper .price {
            margin: .6rem 0 .12rem 0;
            font-size: .3rem;
            color: #b0b0b0;
}
.seckill-view .main .prod-list li .text-wrapper .price strong {
              font-size: .5066rem;
              padding-right: .32rem;
}
.seckill-view .main .prod-list li .text-wrapper .border {
            position: relative;
            display: inline-block;
            padding: 2px 12px;
            border: 1px solid #e53a40;
            border-radius: 20px;
            color: #e53a40;
            overflow: hidden;
}
.seckill-view .main .prod-list li .text-wrapper .mask {
            position: absolute;
            left: 0;
            top: 0;
            width: 50%;
            height: 100%;
            background-color: #e53a40;
            opacity: .4;
}
.seckill-view .main .prod-list li .btn-wrapper {
          position: absolute;
          right: .2rem;
          bottom: .32rem;
}
.seckill-view .main .prod-list li .btn-wrapper .mint-button--small {
            font-size: .3466rem;
            padding: 0;
            line-height: .64rem;
            height: .64rem;
            width: 1.92rem;
            border-radius: 25px;
}
.seckill-view .main .prod-list li .btn-wrapper .mint-button--danger {
            background-color: #e53a40;
}



