
.home-view {
  width: 100%;
  margin-bottom: 1.3333rem;
}
.home-view .mint-tabbar {
    height: 1.3333rem;
    overflow: hidden;
    background-image: none;
    border-top: 1px solid #e4e4e4;
}
.home-view .mint-tabber.is-fixed {
    z-index: 1000;
}
.home-view .mint-tab-item {
    padding: 0;
}
.home-view .mint-tab-item .footer-bar-label {
    display: block;
    font-size: .2rem;
    line-height: .4rem;
    font-family: NotoSansHans;
}
.home-view .mint-tabbar > .mint-tab-item.is-selected .icon {
    color: #e53a40;
    fill: currentColor;
}
.home-view .mint-tab-item-label > a {
    display: block;
    padding-top: .2rem;
    color: #b0b0b0;
    text-decoration: none;
}
.home-view .mint-tab-item.is-selected .mint-tab-item-label .footer-bar-label {
    color: #e53a40;
}
.home-view .mint-tabbar > .mint-tab-item.is-selected {
    background: transparent;
}



