
.swiper-bar {
  background-color: #fff;
  border-bottom: 1px solid #e4e4e4;
  line-height: 1.2rem;
  font-size: .4rem;
}
.swiper-bar .active-color {
    color: #e53a40;
}
.swiper-bar .swiper-slide {
    display: inline-block;
    padding: 0 .4rem;
    width: auto;
}



