
.user-view {
  width: 10rem;
  margin: 0 auto;
  /*font-family: NotoSansHans;*/
}
.user-view .info {
    position: relative;
    width: 100%;
    height: 3.4933rem;
    background-color: #d43b40;
    color: #fff;
}
.user-view .info .img-wrapper {
      padding-top: .5866rem;
}
.user-view .info .img-wrapper img {
        width: 1.6rem;
        height: 1.6rem;
        border-radius: 50%;
        border: 2px solid rgba(255, 255, 255, 0.4);
}
.user-view .info .name {
      font-size: .3733rem;
      font-weight: 300;
      line-height: .8rem;
}
.user-view .info .icon-wrapper {
      position: absolute;
      right: .5866rem;
      top: .5866rem;
}
.user-view .info .icon-set {
      color: #fff;
      width: .58rem;
      height: .58rem;
}
.user-view .btn {
    margin-bottom: .4rem;
    background-color: #fff;
}
.user-view .btn .btn-list {
      width: 100%;
}
.user-view .btn .btn-list:after {
        clear: both;
        display: block;
        content: '';
}
.user-view .btn .btn-list li {
        width: 33.33%;
        height: 1.3333rem;
        float: left;
        overflow: hidden;
}
.user-view .btn .btn-list li button {
          width: 100%;
          height: 100%;
          -webkit-appearance: none;
          background-color: #fff;
          border: none;
}
.user-view .btn .btn-list li button .count {
            font-size: .4rem;
            font-weight: 500;
            color: #222;
            line-height: .6rem;
}
.user-view .btn .btn-list li button .name {
            font-size: .2666rem;
            color: #5a5a5a;
}
.user-view .my-order {
    text-align: left;
    margin-bottom: .4rem;
}
.user-view .my-order .list-wrapper {
      padding: .4rem .2rem;
      background-color: #fff;
}
.user-view .my-order .order-list {
      text-align: center;
      background-color: #fff;
}
.user-view .my-order .order-list li {
        float: left;
        width: 20%;
        color: #5a5a5a;
}
.user-view .my-order .order-list li .icon {
          color: #5a5a5a;
}
.user-view .my-order .order-list li .name {
          line-height: .6rem;
}



