
@charset "UTF-8";
#app {
  /*font-family: 'Microsoft YaHei';*/
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #222;
  font-size: .32rem;
}
#app .mint-button--danger {
    background-color: #e53a40;
}
#app .mint-button--primary {
    background-color: #303030;
}
#app .mint-button--default {
    background-color: #fff;
    border: 1px solid #b0b0b0;
    -webkit-box-shadow: none;
            box-shadow: none;
}

/*svg图标*/
.icon {
  display: inline-block;
  color: #b0b0b0;
  fill: currentColor;
  width: .6rem;
  height: .6rem;
}
.fl {
  float: left;
}
.fr {
  float: right;
}
.clear:after {
  clear: both;
  display: block;
  content: '';
}
button {
  position: relative;
  outline: none;
  overflow: hidden;
}
button::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    opacity: 0;
    background-color: #000;
}
button:active::after {
    opacity: .25;
}



