
.store-view {
  width: 100%;
  font-family: 'mircosoft yahei';
  color: #222;
}
.store-view .active-color {
    color: #e53a40;
}
.store-view .bg {
    width: 100%;
    height: 3.4933rem;
}
.store-view .bg img {
      width: 100%;
      height: 100%;
}
.store-view .vux-sticky-box {
    background-color: #fff;
}
.store-view .store-info {
    padding: 0 .48rem .4rem .48rem;
    text-align: left;
    border-bottom: 1px solid #e4e4e4;
    background-color: #fff;
}
.store-view .store-info .wrapper {
      position: relative;
      padding: .4rem 0 0 2.12rem;
}
.store-view .store-info .img-wrapper {
      position: absolute;
      left: 0;
      top: -.52rem;
      width: 1.8666rem;
      height: 1.8666rem;
}
.store-view .store-info .img-wrapper img {
        width: 100%;
        height: 100%;
}
.store-view .store-info .content-wrapper {
      padding-right: 1.6rem;
}
.store-view .store-info .content-wrapper .store-name {
        font-size: .3733rem;
        font-weight: 500;
}
.store-view .store-info .content-wrapper > p {
        color: #b0b0b0;
        line-height: .6rem;
}
.store-view .store-info .btn-wrapper {
      position: absolute;
      right: 0;
      top: .6rem;
}
.store-view .store-info .mint-button {
      font-size: .32rem;
      height: .6133rem;
      width: 1.4rem;
      line-height: .6133rem;
      padding: 0;
      border: none;
}
.store-view .prod-list {
    padding: .4rem .54rem;
}
.store-view .prod-list li {
      padding: .2rem 0;
}



